import{o as p,c as e,D as t}from"./framework.54301fec.js";const a='{"title":"Глава 16","description":"","frontmatter":{"title":"Глава 16","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-07-20T00:00:00.000Z"},"headers":[{"level":2,"title":"Шестнадцатая глава","slug":"шестнадцатая-гnава"}],"relativePath":"texts/malini-vijayottara/16.md","lastUpdated":1624913133437}',m={},r=t('<h2 id="шестнадцатая-гnава"><a class="header-anchor" href="#шестнадцатая-гnава" aria-hidden="true">#</a> Шестнадцатая глава</h2><p>Теперь поведаю божественную гарвамайи дхарану (<em>созерцание гордыни</em>), наилучшую дхарану состоящую из великой гордости йогинов, о почитаемая йогинами ..1.</p><p>Следует созерцать свое тело как шестнадцатилепесковую чакру, не отклоняясь умом. Созерцая: «это есть Я, в окружении (моих) собственных действий» ..2.</p><p>За три года, йогин станет не подверженым ей (<em>гордости</em>), его нерушимое «мое» будет повсюду и нигде ..3.</p><p>В такой же форме чакры следует следует созерцать свой пупок, созерцая: «Я есть все, во мне все пребывает» ..4.</p><p>Тогда он обретет постижение ахамкары. Что может быть может быть удивительней?</p><p>Созерцая неусыпно в сердечной чакре Меня в своей форме; .5.</p><p>Он достигнет мира солнца, и плода окружения эго. Созерцая по порядку, сине- красный круг и прочее; .6.</p><p>Благодаря этому он достигнет всех десяти направлений. Так описана гарвамайи (дхарана), наделяющая достоинством Праджапати ..7.</p><p>В сердце созерцается восьмилепестковый (лотос), наделенный дхармой и прочими качествами и венчиком, сияющий как диск восходящего солнца, .8.</p><p>За месяц разум станет устойчивым, за шесть месяцев (йогин) станет дающим шрути, за три года он сам станет автором шастр ..9.</p><p>В этом образе следует созерцать себя, (тогда садхака) увидит буддхи таттву, созерцающий брахмана он достигнет знания Иши ..10.</p><p>Взывая к божествам (<em>семь?- текст поврежден</em>), пребывая в самадхи мудрец, благодаря практике, станет устойчивым, и ясно (осознает) даже то, что недостижимо (для понимания) ..11.</p><p>Созерцая по порядку все описанное прежде, начиная с диска, (садхака) обретет могущество Брахмы, пребывающее в окружении буддхи ..12.</p><p>Созерцающий в сердце диск солнца, а внутри него- лунную мандалу, через шесть месяцев такой практики легко обретет божественное зрение, а за три года у него появятся сиддхи.</p><p>Созерцающий там свое тело, обретет там благое достоинство и знание ..13-14.</p><p>Созерцающий сияние в образе лингама, достигнет природы Ишы. Созерцающий, как и прежде, диск (солнца) и десятку прочих, состоящих из десяти;.15.</p><p>Достигнет плода, без сомнения, пребывания окружении (Иши). Их называется двадцать четыре, у каждого пятнадцать;.16.</p><p>Дхарана таттв, начиная с кшамы. Предназначенные все вместе для блага йогинов, они пребывают, поделенные на тринадцать и шесть других ..17.</p><p>Они раскрываются йогинами ради совершенства в йоге. Оставляя свое тело в изначальной форме, ни что иное не следует созерцать;.18.</p><p>(Кроме) белого лотоса, пребывающего над тремя мандалами. Утвердивишь в этом (созерцании садхака) за три месяца станет знающим йогу ..19.</p><p>Он станет свободным от всех болезней, что может быть удивительней? За шесть месяцев еще на земле у него появится постижение ..20.</p><p>За три года, свободный от старости и прочего, он станет зрящим пуруша таттву. В лотосе ниже сердца, (созерцается) тело (размером) шесть ангул;.21.</p><p>В середине него следует созерцать себя, (тогда йогин ) за шесть месяце станет победителем смерти. За три года он достигнет единства с владыкой пуруша таттвы ..22.</p><p>Там созерцается, как прежде, диск (солнца ) и прочее, без сомнения (йогин) обретет пребывание в окружении Пуруши ..23.</p><p>Это описано вкратце знание веданты, поведанное раньше Капилой, и разъясненное Мной ..24.</p><p>Созерцающий свое тело цвета тучи в середине осени, за шесть месяцев обретет (знание) влечения и страсти, без сомнения ..25.</p><p>За год он станет свободным от старости смерти, за три года он достигнет знания великого окружения рага (таттвы) ..26.</p><p>Следует созерцать (свое) тело красного цвета, целиком пребывающее над бровями, в течении шести месяцев, не напрягая ум, ради преодоления страсти и влечения. За год созерцания, он не будет поражен смертью. За три года (он станет) победителем двойственности, и обретет единство с рага (таттвой) ..27-28.</p><p>Созерцая красное (тело) пребывающее в красном лотосе над сердцем с пятью ветвями, достигается плод, описанный раньше по порядку ..29.</p><p>Как и прежде, следует вновь сосредоточено созерцать там диск и прочее, тогда явится, несомненно, плод, происходящий из окружения света ..30.</p><p>Следует созерцать в сердце белый лотос, с раскрытыми лепестками, и венчиком, наполненный божественной амритой, с пестиком, в виде луны ..31.</p><p>Тогда у практикующего из этого лотоса родятся все плоды, посредством кала крамы ..33.</p><p>Созерцая повсюду тело (размером) 4 ангулы, и т.д. как и прежде, он обретет всепревосходящий (плод) из видья таттвы ..34.</p><p>От сердца, расположив на пол-ангулы одну над другой, следует созерцать последовательно 3 чакры, по порядку: красную, синюю и белую ..35.</p><p>Там каждый из узлов титтхи есть пуруша, соответствующего цвета, (следует созерцать), как сказано, диск и т.д. Такова эта великая триада таттв ..36.</p><p>Разделение 13 на конце знают мудрые, Теперь разъясняются две таттвы – разделяемые на 11 ..37.</p><p>В чакре о пяти спицах, простирающейся от горла до пупка, следует созерцать себя, в изначальной форме, подобной блеску глаз ..38.</p><p>Практикуя реальность во всех адхвах, от земли и до кала таттвы, владыка йоги не будет подвержен (влиянию) времени ..39.</p><p>В диске и прочем пребывающие, созерцаемые йогинами, пребывают удивительное Время и его плод .40.</p><p>Йогин делающий усточивым ум в пространстве горла изо дня в день, достигнет плода превосходства над майей, пребывая в диске и т.п ..41.</p><p>Созерцающий Раху, схватывающего диск луны в отверстии горла, не будет подвержен влиянию майи ..42.</p><p>Созерцающий там солнце в небе, подобное (жемчужине) а также сияющее тело и т.д. достигнет высшего владычества, .43.</p><p>Следует созерцать образ полуденного (солнца), пребывающего в зените, образ всей мантра чакры, и ее источник ..44.</p><p>Затем, благодаря кала краме йогин обретет природу мантры. Плод соединения там, как прежде было сказано, наделит его всем ..45.</p><p>Созерцая там образ, он обретет (природу) мантреши. Созерцая свет, сияющий ниже этого места, он станет падшим ..46.</p><p>Поэтому, созерцая этот свет, проникающий изнутри и снаружи, человек не утеряет положение матрешвары ..47.</p><p>Приняв падмасану, йогин, созерцая высшую биджу, пусть поместит сознание между бровей, (не глядя) ни на что перед собой ..48.</p><p>Закрыв глаза, с удовлетворенной душой, без (слушания) звуков, и осматривания (форм) он увидит там пурушу, размером 12 ангул ..49.</p><p>Сделав ум сосредоточенным на нем, более трех месяцев, его, наполненного всеми частями в форме неподвижного света;.50.</p><p>Удовлетворенного, цвета луны, он увидит божественным зрением. Узрев того божественного Пурушу, он обретет знание времени ..51.</p><p>Если он будет без головы, (йогин) обретет за шесть месяцев смерть внутри и снаружи. За это время знающий йогу, должен выполнить желаемое ..52.</p><p>Следует созерцать над брахмарандхрой безупречный диск луны, источающий поток божественной амриты, наполняющий его собственное тело ..53.</p><p>Наполняя себя им, (сопровождаемый) огнем сознания, созерцая (себя так), снаружи и внутри, за 10 дней он станет победителем смерти ..54.</p><p>Ради уничтожения великой болезни, следует практиковать эту йогу. Ради уничтожения каждой болезни следует созерцать каждый орган ..55.</p><p>Когда он увидит его дымчатого цвета, тогда будет великая болезнь, (если он будет) черным, то он обретет проказу, (если) синий – холодобоязнь ..56.</p><p>Если он не видит своих членов, это указывает на соответствующие болезни. Болезнь слепоты, отсутствие носа, и т.д.;.57.</p><p>У себя и у других. Йогин, пребывающий на пути йоги, за пять лети обретет (знание) видья таттвы, о Владычица!.58.</p><p>То, что познает и вкушает постоянно, не будет им утеряно, Там, пребывая в созерцаемом сияющем (теле), он пребудет во всех телах ..59.</p><p>Он обретет все, как было сказано ранее, посредством этой калакрамы. В созерцании (света) непрерывно пребывающего вверху;.60.</p><p>Он (не утеряет) природу мантрешвары, и не вернется вновь.Так, созерцающий великое сияние в области лба, он быстро увидит по порядку восемь цветов. Цвет тучи, цвет Шитиканты (<em>горла Шивы</em>);.61-62.</p><p>Цвета раджаварта (<em>ляпись-лазурь</em>), цвета вайдурья (<em>кошачий глаз</em>), цвета пушпараги (<em>топаз</em>), следующий – цвет прабалаки (<em>коралл</em>) ..63.</p><p>Цвета падмараги (<em>розовый</em>), последний- цвет луны. Увидев этот высший свет, он обретет божественное знание;.64.</p><p>Состояние вихары и прочее, затем наступает Все. При созерцании, проникающим сверху и снизу он не сойдет с этого положения ..65.</p><p>Итак поведаны все разнообразные признаки. Теперь наставлю о различении сознания ..66.</p><p>Этих качеств насчитывается 8, от Пишачей, до ананты. Такой же вид качеств. Следует сделать ум устойчивым в Ише ..67.</p><p>Итак, поведаны о пути поклонения йогинами, по порядку, вплоть до положения Ишвары, ради совершенства в йоге ..68.</p><p>[small]Такова в священной «Малини виджайоттара тантре» шестнадцатая глава [/small]</p>',68);m.render=function(t,a,m,l,i,s){return p(),e("div",null,[r])};export default m;export{a as __pageData};
